from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Dict, Optional
from enum import Enum
import time

class ExecutionMode(Enum):
    QUANTUM = 'quantum'
    CLASSICAL = 'classical'
    HYBRID = 'hybrid'

@dataclass
class ExecutionResult:
    success: bool
    mode: ExecutionMode
    result: Dict
    time_ms: float
    error: Optional[str] = None

class QuantumModule(ABC):
    def __init__(self, fallback_enabled: bool = True, quality_threshold: float = 0.8):
        self.fallback_enabled = fallback_enabled
        self.quality_threshold = quality_threshold

    @abstractmethod
    def quantum_execute(self, params: Dict) -> Dict:
        pass

    @abstractmethod
    def classical_execute(self, params: Dict) -> Dict:
        pass

    def execute(self, params: Dict, mode: ExecutionMode = ExecutionMode.HYBRID) -> ExecutionResult:
        start = time.time()
        try:
            if mode == ExecutionMode.CLASSICAL:
                result = self.classical_execute(params)
                used_mode = ExecutionMode.CLASSICAL
            elif mode == ExecutionMode.QUANTUM:
                result = self.quantum_execute(params)
                used_mode = ExecutionMode.QUANTUM
            else:  # HYBRID
                try:
                    result = self.quantum_execute(params)
                    used_mode = ExecutionMode.QUANTUM
                    if result.get('quality', 1.0) < self.quality_threshold and self.fallback_enabled:
                        result = self.classical_execute(params)
                        used_mode = ExecutionMode.CLASSICAL
                except Exception as e:
                    if self.fallback_enabled:
                        result = self.classical_execute(params)
                        used_mode = ExecutionMode.CLASSICAL
                    else:
                        raise

            return ExecutionResult(
                success=True,
                mode=used_mode,
                result=result,
                time_ms=(time.time() - start) * 1000
            )
        except Exception as e:
            return ExecutionResult(
                success=False,
                mode=mode,
                result={},
                time_ms=(time.time() - start) * 1000,
                error=str(e)
            )

