from dataclasses import dataclass
from typing import List, Dict
from enum import Enum
import numpy as np

class Mode(Enum):
    QUANTUM = 'quantum'
    CLASSICAL = 'classical'

@dataclass
class ExecutionLog:
    module: str
    success: bool
    mode: Mode
    time_ms: float
    quality: float

class Dashboard:
    def __init__(self):
        self.logs: List[ExecutionLog] = []

    def add_log(self, log: ExecutionLog):
        self.logs.append(log)

    def get_metrics(self) -> Dict:
        if not self.logs:
            return {'total': 0}

        quantum_count = sum(1 for l in self.logs if l.mode == Mode.QUANTUM)
        success_count = sum(1 for l in self.logs if l.success)

        return {
            'total': len(self.logs),
            'quantum_executions': quantum_count,
            'classical_executions': len(self.logs) - quantum_count,
            'success_rate': success_count / len(self.logs),
            'avg_time_ms': np.mean([l.time_ms for l in self.logs]),
            'avg_quality': np.mean([l.quality for l in self.logs if l.success])
        }

    def by_module(self) -> Dict[str, Dict]:
        result = {}
        modules = set(l.module for l in self.logs)

        for module in modules:
            module_logs = [l for l in self.logs if l.module == module]
            result[module] = {
                'executions': len(module_logs),
                'success_rate': sum(1 for l in module_logs if l.success) / len(module_logs),
                'avg_time_ms': np.mean([l.time_ms for l in module_logs])
            }

        return result

