from dataclasses import dataclass
from typing import List, Dict

@dataclass
class ChecklistItem:
    name: str
    category: str
    required: bool
    completed: bool = False

class ReadinessChecker:
    def __init__(self):
        self.items: List[ChecklistItem] = []

    def add_item(self, item: ChecklistItem):
        self.items.append(item)

    def complete(self, name: str):
        for item in self.items:
            if item.name == name:
                item.completed = True
                return

    def blocking_items(self) -> List[str]:
        return [i.name for i in self.items if i.required and not i.completed]

    def readiness_score(self) -> Dict:
        if not self.items:
            return {'score': 0, 'required_complete': 0, 'required_total': 0}

        required = [i for i in self.items if i.required]
        required_complete = sum(1 for i in required if i.completed)
        total_complete = sum(1 for i in self.items if i.completed)

        return {
            'score': total_complete / len(self.items) * 100,
            'required_complete': required_complete,
            'required_total': len(required),
            'ready': required_complete == len(required)
        }

    def is_ready(self) -> bool:
        return len(self.blocking_items()) == 0
